from urllib.parse import urlparse

app = Flask(__name__)


@app.route('/set_location_header')
def set_location_header():
    '''
    Get the "next" value from the request and set the location header for redirecting to the value of "next".
    Only allow relative URLs to prevent open redirects.
    '''
    next_url = request.args.get('next', '/')

    # Validate that the URL is relative and safe
    parsed = urlparse(next_url)
    # Allow only relative paths: no scheme, no netloc, and does not start with //
    if not parsed.scheme and not parsed.netloc and not next_url.startswith('//'):
